//Import Field datas from txt files generated by COMSOL

//Local software path
var path = UserSetting.SampleCodeDir;

// Import realpart of field datas from txt files generated by COMSOL
var vRe = Import.Txt2Scat1DRealData(filePath: path + @"\ImportExportFiles\Incidence_RE.txt", columnSeparator: ';', startLine: 8);
// Import imagepart of field datas from txt files generated by COMSOL
var vIm = Import.Txt2Scat1DRealData(filePath: path + @"\ImportExportFiles\Incidence_IM.txt", columnSeparator: ';', startLine: 8);
// Construct complex field datas
var v = VMath.Construct(realPart: vRe.Values,imagPart: vIm.Values);
// The points of ReEzCom is same as the points of ImEzCom
var scat = new ScatInfo1D(vRe.Points);
var vScat = new Scat1DCplxData(scat, v);

// Show the filed
VFrame.CreateShow(sv: vScat,title: "Data from COMSOL");
